export default function UnidadesScreen({ navigation }) {
  const [localizacao, setLocalizacao] = useState(null)
  const [erro, setErro] = useState(null)
  const [carregando, setCarregando] = useState(true)

  useEffect(() => {
    async function pegarLocalizacao() {
      
      const { status } = await Location.requestForegroundPermissionsAsync()

      if (status !== 'granted') {
        setErro('Permissão de localização negada')
        setCarregando(false)
        return
      }
      const pos = await Location.getCurrentPositionAsync({})
      setLocalizacao(pos.coords)
      setCarregando(false)
    }

    pegarLocalizacao()
  }, [])

  const unidadesComDistancia = UNIDADES.map((u) => ({
    ...u,
    distancia: localizacao
      ? calcularDistancia(localizacao.latitude, localizacao.longitude, u.lat, u.lon)
      : null,
  })).sort((a, b) => {
  if (a.distancia === null) return 1
  if (b.distancia === null) return -1
  return a.distancia - b.distancia
})

  return (
    <View style={styles.container}>

     
      <View style={styles.header}>
        <Pressable onPress={() => navigation.goBack()}>
          <Text style={styles.voltar}>← Voltar</Text>
        </Pressable>
        <Text style={styles.headerTitulo}>Unidades de Saúde</Text>
        <Text style={styles.headerSub}>
          {localizacao ? 'Ordenadas pela mais próxima' : 'Buscando sua localização...'}
        </Text>
      </View>

      
      {carregando && (
        <View style={styles.loading}>
          <ActivityIndicator size="large" color="#1B6B4A" />
          <Text style={styles.loadingText}>Buscando sua localização...</Text>
        </View>
      )}

     
      {erro && (
        <View style={styles.erroBox}>
          <Text style={styles.erroText}>{erro}</Text>
        </View>
      )}

      
      {!carregando && (
        <FlatList
          data={unidadesComDistancia}
          keyExtractor={(item) => item.id}
          contentContainerStyle={styles.lista}
          renderItem={({ item }) => (
            <Pressable
              style={({ pressed }) => [styles.card, pressed && styles.cardPressed]}
              onPress={() => navigation.navigate('MainTabs', {
                screen: 'Mapa',
                params: { unidade: item }
              })}
            >
             
              <Image source={{ uri: item.foto }} style={styles.foto} />

            
              <View style={[
                styles.badge,
                { backgroundColor: item.aberto ? '#E8F5EE' : '#FFF0F0' }
              ]}>
                <Text style={[
                  styles.badgeText,
                  { color: item.aberto ? '#1B6B4A' : '#E53935' }
                ]}>
                  {item.aberto ? '● Aberto' : '● Fechado'}
                </Text>
              </View>

             
              <View style={styles.cardInfo}>
                <View style={styles.cardTopo}>
                  <View style={[styles.tipoBolinha, { backgroundColor: item.cor }]} />
                  <Text style={styles.cardTipo}>{item.tipo}</Text>
                </View>

                <Text style={styles.cardNome}>{item.nome}</Text>
                <Text style={styles.cardEndereco}>📍 {item.endereco}</Text>

                <View style={styles.cardRodape}>
                  <Text style={styles.cardDistancia}>
                    {item.distancia ? `📏 ${item.distancia} km de você` : '📏 Calculando...'}
                  </Text>
                  
                    <Text style={styles.cardVerMapa}>Ver no mapa</Text>
                  
                </View>
              </View>
            </Pressable>
          )}
        />
      )}

    </View>
  )
}

